// pages/colorPicker/index.js
Page({

    /**
     * 页面的初始数据
     */
    data: {
        isShowColor: false,
        color: null,
        color1: null,
        color2: null,
        color3: null,
        title: "",
        initColor: "",
        commonColor: "#000000,#ffffff,#ff0000,#ffa500,#00ff00,#0000ff,#ff00ff,#00ffff,#ffff00,#70db93,#cccccc,#999999",
    },

    /**
     * 生命周期函数--监听页面加载
     */
    onLoad(options) {

    },
    colorConfirm(e) {
        const colorObj = e.detail;
        let obj = {
            isShowColor: false
        };
        obj[this.colorName] = colorObj;
        this.setData(obj);
        this.colorName = "";
    },
    colorCancel() {
        this.colorName = "";
        this.setData({
            isShowColor: false
        });
    },
    showColorPicker(e) {
        this.colorName = e.currentTarget.dataset.name;
        const title = e.currentTarget.dataset.title;
        const color = e.currentTarget.dataset.color;
        this.setData({
            isShowColor: true,
            title: title || "",
            initColor: color || ""
        });
    }
})